// n8n Code Node - Updated for Master Profile
const allData = items.map(item => item.json);

const profile = {
  personal: {},
  education_details: {}, // Changed to object to capture specific keys like Degree, University
  links: {},
  documents: {}, // New category for Drive links
  experience: [], // New category
  leadership: [], // New category
  projects: [],
  certifications: [],
  volunteering: [],
  skills: {
    technical: [],
    design: [],
    soft: [],
    ai_llm: [],
    devops: [],
    languages: [] 
  }
};

for (const row of allData) {
  const key = row.Key;
  let val = row.Value;

  if (!key || !val) continue;

  // Clean up value if string
  if (typeof val === 'string') val = val.trim();

  // --- 1. PROJECTS ---
  if (key.startsWith('Project:')) {
    const projectName = key.replace('Project:', '').trim();
    profile.projects.push({
      name: projectName,
      details: val
    });

  // --- 2. EXPERIENCE ---
  } else if (key.startsWith('Experience:')) {
    const company = key.replace('Experience:', '').trim();
    profile.experience.push({
      company: company,
      role_details: val
    });

  // --- 3. LEADERSHIP ---
  } else if (key.startsWith('Leadership:')) {
    const org = key.replace('Leadership:', '').trim();
    profile.leadership.push({
      organization: org,
      role: val
    });

  // --- 4. DOCUMENTS ---
  } else if (key.startsWith('Document:')) {
    const docName = key.replace('Document:', '').trim();
    profile.documents[docName] = val;

  // --- 5. CERTIFICATIONS & VOLUNTEERING ---
  } else if (key.startsWith('Certification:')) {
    const certName = key.replace('Certification:', '').trim();
    profile.certifications.push({ name: certName, details: val });
  } else if (key.startsWith('Volunteering:')) {
    const volName = key.replace('Volunteering:', '').trim();
    profile.volunteering.push({ name: volName, role: val });

  // --- 6. LINKS & URLS ---
  } else if (key.includes('URL') || key.includes('Link')) {
    const cleanKey = key.replace(' URL', '').replace(' Link', '').trim();
    profile.links[cleanKey] = val;

  // --- 7. SKILLS (Comma Separated Splitting) ---
  } else if (key.startsWith('Skill:')) {
    const skillList = val.split(',').map(s => s.trim()); // Split "React, Node" into array

    if (key.includes('Design')) profile.skills.design.push(...skillList);
    else if (key.includes('Soft')) profile.skills.soft.push(...skillList);
    else if (key.includes('AI') || key.includes('LLM')) profile.skills.ai_llm.push(...skillList);
    else if (key.includes('DevOps')) profile.skills.devops.push(...skillList);
    else if (key.includes('Languages')) profile.skills.languages.push(...skillList);
    else profile.skills.technical.push(...skillList);

  // --- 8. EDUCATION SPECIFICS ---
  } else if (['University', 'Degree', 'Major', 'CGPA', 'Current Semester', 'Year of Graduation', 'High School (12th)', 'High School (10th)'].some(k => key.includes(k))) {
    profile.education_details[key] = val;

  // --- 9. PERSONAL (Catch All) ---
  } else {
    profile.personal[key] = val;
  }
}

// Return raw object (NOT stringified) for proper mapping
return [{ json: profile }];
